<?php
namespace Tests\Feature\Hr;use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Compensation\Actions\ManageSalaryBandAction;use App\Modules\Hr\Compensation\Actions\ManageSalaryRecordAction;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Personnel\Models\HrEmployee;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class CompensationWorkflowTest extends TestCase{use RefreshHrDatabase;public function test_salary_is_encrypted_versioned_and_requires_second_approver():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$maker=User::factory()->create(['role_id'=>$role]);$approver=User::factory()->create(['role_id'=>$role]);$this->actingAs($maker);$tenant=LegalEntity::create(['user_id'=>$maker->id,'name'=>'Ücret','tax_number'=>'9191919191','is_active'=>true]);app(TenantContext::class)->set($tenant);$employee=HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$tenant->id,'employee_number'=>'SAL1','national_id_encrypted'=>'enc','national_id_hash'=>'salary-employee','national_id_last_four'=>'0001','first_name'=>'Ücret','last_name'=>'Çalışan','status'=>'active']);$band=app(ManageSalaryBandAction::class)->execute(['code'=>'B1','name'=>'Uzman','minimum'=>40000,'midpoint'=>50000,'maximum'=>60000,'effective_from'=>today()]);$record=app(ManageSalaryRecordAction::class)->propose($employee,52000,today()->toDateString(),'Yıllık değerlendirme',$band);$raw=DB::table('hr_salary_records')->where('id',$record->id)->value('gross_salary_encrypted');$this->assertStringNotContainsString('52000',$raw);try{app(ManageSalaryRecordAction::class)->approve($record);$this->fail('Hazırlayan onaylayamamalı.');}catch(\Symfony\Component\HttpKernel\Exception\HttpException $e){$this->assertSame(422,$e->getStatusCode());}$this->actingAs($approver);$approved=app(ManageSalaryRecordAction::class)->approve($record->fresh());$this->assertSame('approved',$approved->status);$this->assertSame(52000.0,$approved->grossSalary());}}
